  display: flex;
  gap: 0.5rem;
}

.testUsersCountBtn {
  flex: 1;
  padding: 0.5rem 0;
  background: rgba(theme.$color-light-primary, 0.08);
  border: 1px solid rgba(theme.$color-light-primary, 0.15);
  border-radius: theme.$border-radius;
  color: theme.$color-text-primary;
  font-size: 1.3rem;
  cursor: pointer;
  transition: background-color 0.15s ease;

  &:hover:not(:disabled) {
    background: rgba(theme.$color-light-primary, 0.18);
  }

  &:disabled {
    opacity: 0.45;
    cursor: not-allowed;
  }
}

import {
  AudioMutedOutlined,
  AudioOutlined,
  CheckCircleOutlined,
  CrownOutlined,
  EyeInvisibleOutlined,
  EyeOutlined,
  LogoutOutlined,
  MoreOutlined,
  ReloadOutlined,
  SettingOutlined,
  SoundOutlined,
  VideoCameraAddOutlined,
} from "@ant-design/icons";
import Tippy from "@tippyjs/react";
import classNames from "classnames";
import { observer } from "mobx-react-lite";
import { useTranslation } from "react-i18next";

import { ModalNames } from "@/components/Modals/Modal.types.ts";
import { useGMMenu } from "@/hooks/useGMMenu.ts";
import { modalStore } from "@/store/modalStore.ts";
import { Dropdown, Menu, MenuItem, MenuSeparator } from "@/UI";

import styles from "./GMMenu.module.scss";

export const GMMenu = observer(() => {
  const { t } = useTranslation();
  const { openModal } = modalStore;
  const {
    isMenuOpen,
    setIsMenuOpen,
    isIGM,
    gameFlow,
    onMuteAll,
    onUnmuteAll,
    onDisableAllCameras,
    onEnableAllCameras,
    onRestartGame,
    onFinishGame,
    onLeaveGame,
  } = useGMMenu();

  return (
    <div className={styles.gmMenuContainer}>
      <Dropdown
        trigger={
          <Tippy
            content={t("gmMenu.title")}
            delay={[500, 0]}
            theme="role-tooltip"
          >
            <button
              className={classNames(styles.controlBtn, {
                [styles.active]: isMenuOpen,
              })}
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              aria-label={t("gmMenu.title")}
            >
              <MoreOutlined />
            </button>
          </Tippy>
        }
        content={
          <Menu>
            {isIGM && (
              <>
                <MenuItem
                  icon={<AudioMutedOutlined />}
                  label={t("gmMenu.muteAll")}
                  onClick={onMuteAll}
                />

                <MenuItem
                  icon={<AudioOutlined />}
                  label={t("gmMenu.unmuteAll")}
                  onClick={onUnmuteAll}
                />

                <MenuSeparator />

                <MenuItem
                  icon={<EyeInvisibleOutlined />}
                  label={t("gmMenu.disableAllCameras")}
                  onClick={onDisableAllCameras}
                />

                <MenuItem
                  icon={<EyeOutlined />}
                  label={t("gmMenu.enableAllCameras")}
                  onClick={onEnableAllCameras}
                />

                {!gameFlow.isStarted && (
                  <>
                    <MenuSeparator />
                    <MenuItem
                      icon={<SettingOutlined />}
                      label={t("game.settings")}
                      onClick={() => {
                        setIsMenuOpen(false);
                        openModal(ModalNames.GameSettingsModal, {});
                      }}
                    />
                  </>
                )}

                {gameFlow.isStarted && (
                  <>
                    <MenuSeparator />

                    <MenuItem
                      icon={<ReloadOutlined />}
                      label={t("gmMenu.restartGame")}
                      onClick={onRestartGame}
                    />

                    <MenuItem
                      icon={<CheckCircleOutlined />}
                      label={t("gmMenu.finishGame")}
                      onClick={onFinishGame}
                    />
                  </>
                )}

                <MenuSeparator />
              </>
            )}

            <MenuItem
              icon={<LogoutOutlined />}
              label={t("gmMenu.leaveGame")}
              onClick={onLeaveGame}
            />
          </Menu>
        }
        isOpen={isMenuOpen}
        onToggle={setIsMenuOpen}
        placement="bottom-end"
      />
    </div>
  );
});

GMMenu.displayName = "GMMenu";

import {
  AudioMutedOutlined,
  AudioOutlined,
  CheckCircleOutlined,
  ExperimentOutlined,
  EyeInvisibleOutlined,
  EyeOutlined,
  LogoutOutlined,
  MoreOutlined,
  ReloadOutlined,
  SettingOutlined,
} from "@ant-design/icons";
import Tippy from "@tippyjs/react";
import classNames from "classnames";
import { observer } from "mobx-react-lite";
import { useTranslation } from "react-i18next";

import { ModalNames } from "@/components/Modals/Modal.types.ts";
import { useGMMenu } from "@/hooks/useGMMenu.ts";
import { modalStore } from "@/store/modalStore.ts";
import { Dropdown, Menu, MenuItem, MenuSeparator } from "@/UI";

import styles from "./GMMenu.module.scss";

const TEST_USER_PRESETS = [3, 5, 7, 9, 11] as const;

export const GMMenu = observer(() => {
  const { t } = useTranslation();
  const { openModal } = modalStore;
  const {
    isMenuOpen,
    setIsMenuOpen,
    isIGM,
    gameFlow,
    onMuteAll,
    onUnmuteAll,
    onDisableAllCameras,
    onEnableAllCameras,
    onRestartGame,
    onFinishGame,
    onLeaveGame,
    // TODO: remove — temporary for layout stress-testing
    onAddTestUsers,
    isAddingTestUsers,
  } = useGMMenu();

  return (
    <div className={styles.gmMenuContainer}>
      <Dropdown
        trigger={
          <Tippy
            content={t("gmMenu.title")}
            delay={[500, 0]}
            theme="role-tooltip"
          >
            <button
              className={classNames(styles.controlBtn, {
                [styles.active]: isMenuOpen,
              })}
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              aria-label={t("gmMenu.title")}
            >
              <MoreOutlined />
            </button>
          </Tippy>
        }
        content={
          <Menu>
            {isIGM && (
              <>
                <MenuItem
                  icon={<AudioMutedOutlined />}
                  label={t("gmMenu.muteAll")}
                  onClick={onMuteAll}
                />

                <MenuItem
                  icon={<AudioOutlined />}
                  label={t("gmMenu.unmuteAll")}
                  onClick={onUnmuteAll}
                />

                <MenuSeparator />

                <MenuItem
                  icon={<EyeInvisibleOutlined />}
                  label={t("gmMenu.disableAllCameras")}
                  onClick={onDisableAllCameras}
                />

                <MenuItem
                  icon={<EyeOutlined />}
                  label={t("gmMenu.enableAllCameras")}
                  onClick={onEnableAllCameras}
                />

                {!gameFlow.isStarted && (
                  <>
                    <MenuSeparator />
                    <MenuItem
                      icon={<SettingOutlined />}
                      label={t("game.settings")}
                      onClick={() => {
                        setIsMenuOpen(false);
                        openModal(ModalNames.GameSettingsModal, {});
                      }}
                    />
                  </>
                )}

                {gameFlow.isStarted && (
                  <>
                    <MenuSeparator />

                    <MenuItem
                      icon={<ReloadOutlined />}
                      label={t("gmMenu.restartGame")}
                      onClick={onRestartGame}
                    />

                    <MenuItem
                      icon={<CheckCircleOutlined />}
                      label={t("gmMenu.finishGame")}
                      onClick={onFinishGame}
                    />
                  </>
                )}

                <MenuSeparator />
              </>
            )}

            {/* TODO: remove — temporary layout stress test */}
            {/* <div className={styles.testUsersSection}>
              <span className={styles.testUsersLabel}>
                <ExperimentOutlined />
                {isAddingTestUsers
                  ? t("gmMenu.addTestUsersLoading")
                  : t("gmMenu.addTestUsers")}
              </span>
              <div className={styles.testUsersCountRow}>
                {TEST_USER_PRESETS.map((count) => (
                  <button
                    key={count}
                    className={styles.testUsersCountBtn}
                    onClick={() => {
                      onAddTestUsers(count);
                      setIsMenuOpen(false);
                    }}
                    disabled={isAddingTestUsers}
                    aria-label={`Add ${count} test players`}
                  >
                    {count}
                  </button>
                ))}
              </div>
            </div>

            <MenuSeparator /> */}

            <MenuItem
              icon={<LogoutOutlined />}
              label={t("gmMenu.leaveGame")}
              onClick={onLeaveGame}
            />
          </Menu>
        }
        isOpen={isMenuOpen}
        onToggle={setIsMenuOpen}
        placement="bottom-end"
      />
    </div>
  );
});

GMMenu.displayName = "GMMenu";

@use "../../styles/theme.scss";

.container {
  display: grid;
  justify-items: center;
  align-items: center;
  gap: 0.5rem;
  height: 100%;
  padding: 4px;
  position: relative;

  &.twoGrid {
    grid-template-columns: repeat(2, 1fr);
    grid-template-rows: repeat(2, 1fr);
  }

  &.threeGrid {
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: repeat(2, 1fr);
  }

  &.fourGrid {
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(3, 1fr);
  }

  &.fiveGrid {
    grid-template-columns: repeat(5, 1fr);
    grid-template-rows: repeat(3, 1fr);
  }
}

// Explicit class for motion.div grid cells — avoids bleeding into fixed-position videos
.gridCell {
  width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 0;
}

// Applied when the local player's video is in fixed-corner mode (isMyAfterStart).
// Framer-motion keeps a non-none CSS `transform` on motion.div even after animation completes.
// Any non-none transform creates a new containing block for position:fixed descendants,
// breaking .myVideoContainer positioning. !important overrides framer-motion's inline styles.
.noTransform {
  transform: none !important;
  will-change: auto !important;
}

.votingTimerContainer {
  position: absolute;
  bottom: 20px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 100;
}

@use "../../styles/theme.scss";

.container {
  display: grid;
  justify-items: center;
  align-items: center;
  gap: 0.5rem;
  height: 100%;
  padding: 4px;
  position: relative;

  &.twoGrid {
    grid-template-columns: repeat(2, 1fr);
    grid-template-rows: repeat(2, 1fr);
  }

  &.threeGrid {
    grid-template-columns: repeat(3, 1fr);
    grid-template-rows: repeat(2, 1fr);
  }

  &.fourGrid {
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(3, 1fr);
  }

  &.fiveGrid {
    grid-template-columns: repeat(5, 1fr);
    grid-template-rows: repeat(3, 1fr);
  }

  // >10 players + active speaker: small row / big speaker / small row
  &.sandwichGrid {
    grid-template-columns: repeat(5, 1fr);
    grid-template-rows: repeat(4, 1fr);
  }
}

