import { useCallback, useState } from "react";

import { registerOrLoginTestUser } from "@/api/auth/testUsersApi.ts";
import { addUserToGame } from "@/api/game/api.ts";
import { TEST_USER_CREDENTIALS } from "@/config/testUsers.ts";
import { rootStore } from "@/store/rootStore.ts";

export const useAddTestUsers = () => {
  const [isAddingTestUsers, setIsAddingTestUsers] = useState(false);
  const { gamesStore, usersStore } = rootStore;

  const onAddTestUsers = useCallback(async (count: number) => {
    const { activeGameId, activeGamePlayers } = gamesStore;

    if (!activeGameId) return;

    setIsAddingTestUsers(true);

    // Clamp to available credentials
    const credentials = TEST_USER_CREDENTIALS.slice(0, count);

    try {
      for (const credential of credentials) {
        const user = await registerOrLoginTestUser(credential);

        if (!activeGamePlayers.includes(user.id)) {
          // Update the local game store with the BE response so
          // activeGamePlayers is immediately visible to all observers
          const response = await addUserToGame({ gameId: activeGameId, userId: user.id });
          gamesStore.updateGame(response.data);
        }

        usersStore.setUser({ ...user, isOnline: true });
      }

      // Enable mock streams via the shared MobX store so every
      // useMockStreams() instance (VideoGrid, useGridLayout, etc.) reacts
      if (!gamesStore.mockStreamsEnabled) {
        gamesStore.setMockStreamsEnabled(true);
      }
    } catch (error) {
      console.error("[useAddTestUsers] Failed to add test users:", error);
    } finally {
      setIsAddingTestUsers(false);
    }
  }, [gamesStore, usersStore]);

  return { onAddTestUsers, isAddingTestUsers };
};

import { useCallback, useState } from "react";
import { useNavigate } from "react-router-dom";

import { updateGameGM } from "@/api/game/api.ts";
import { useFinishGameMutation, useRestartGameMutation } from "@/api/game/queries.ts";
import { ModalNames } from "@/components/Modals/Modal.types.ts";
import { useBatchMediaControls } from "@/hooks/useBatchMediaControls.ts";
import { useMockStreams } from "@/hooks/useMockStreams.ts";
import { routes } from "@/router/routs.ts";
import { rootStore } from "@/store/rootStore.ts";

export const useGMMenu = () => {
  const navigate = useNavigate();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const { gamesStore, usersStore, isIGM } = rootStore;
  const { activeGameId, activeGameGm, gameFlow } = gamesStore;
  const { myId } = usersStore;

  const { unmuteAll, muteAllExceptGM, disableAllCamerasExceptGM, enableAllCameras } = useBatchMediaControls();

  const { mockStreamsEnabled, handleToggleMockStreams } = useMockStreams();
  const { mutate: restartGame } = useRestartGameMutation();
  const { mutate: finishGame } = useFinishGameMutation();

  const onMakeMeGM = useCallback(async () => {
    if (!activeGameId || !myId) return;

    try {
      await updateGameGM({
        gameId: activeGameId,
        userId: myId,
      });
      setIsMenuOpen(false);
    } catch (error) {
      console.error("Failed to set you as GM:", error);
    }
  }, [activeGameId, myId]);

  const onToggleMockStreams = useCallback(() => {
    handleToggleMockStreams();
    setIsMenuOpen(false);
  }, [handleToggleMockStreams]);

  const onMuteAll = useCallback(() => {
    muteAllExceptGM(activeGameGm);
    setIsMenuOpen(false);
  }, [activeGameGm, muteAllExceptGM]);

  const onUnmuteAll = useCallback(() => {
    unmuteAll();
    setIsMenuOpen(false);
  }, [unmuteAll]);

  const onDisableAllCameras = useCallback(() => {
    disableAllCamerasExceptGM(activeGameGm);
    setIsMenuOpen(false);
  }, [activeGameGm, disableAllCamerasExceptGM]);

  const onEnableAllCameras = useCallback(() => {
    enableAllCameras();
    setIsMenuOpen(false);
  }, [enableAllCameras]);

  const onRestartGame = useCallback(() => {
    if (!activeGameId) return;

    setIsMenuOpen(false);
    rootStore.modalStore.openModal(ModalNames.ConfirmRestartModal, {
      onConfirm: () => restartGame(activeGameId),
    });
  }, [activeGameId, restartGame]);

  const onFinishGame = useCallback(() => {
    if (!activeGameId) return;

    finishGame(activeGameId);
    setIsMenuOpen(false);
  }, [activeGameId, finishGame]);

  const onLeaveGame = useCallback(() => {
    setIsMenuOpen(false);
    navigate(routes.home);
  }, [navigate]);

  return {
    isMenuOpen,
    setIsMenuOpen,
    isIGM,
    mockStreamsEnabled,
    gameFlow,
    onMakeMeGM,
    onToggleMockStreams,
    onMuteAll,
    onUnmuteAll,
    onDisableAllCameras,
    onEnableAllCameras,
    onRestartGame,
    onFinishGame,
    onLeaveGame,
  };
};

import { useCallback, useState } from "react";
import { useNavigate } from "react-router-dom";

import { updateGameGM } from "@/api/game/api.ts";
import { useFinishGameMutation, useRestartGameMutation } from "@/api/game/queries.ts";
import { ModalNames } from "@/components/Modals/Modal.types.ts";
import { useAddTestUsers } from "@/hooks/useAddTestUsers.ts";
import { useBatchMediaControls } from "@/hooks/useBatchMediaControls.ts";
import { useMockStreams } from "@/hooks/useMockStreams.ts";
import { routes } from "@/router/routs.ts";
import { rootStore } from "@/store/rootStore.ts";

export const useGMMenu = () => {
  const navigate = useNavigate();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const { gamesStore, usersStore, isIGM } = rootStore;
  const { activeGameId, activeGameGm, gameFlow } = gamesStore;
  const { myId } = usersStore;

  const { unmuteAll, muteAllExceptGM, disableAllCamerasExceptGM, enableAllCameras } = useBatchMediaControls();

  const { mockStreamsEnabled, handleToggleMockStreams } = useMockStreams();
  const { mutate: restartGame } = useRestartGameMutation();
  const { mutate: finishGame } = useFinishGameMutation();
  // TODO: remove — temporary for layout stress-testing
  const { onAddTestUsers, isAddingTestUsers } = useAddTestUsers();

  const onMakeMeGM = useCallback(async () => {
    if (!activeGameId || !myId) return;

    try {
      await updateGameGM({
        gameId: activeGameId,
        userId: myId,
      });
      setIsMenuOpen(false);
    } catch (error) {
      console.error("Failed to set you as GM:", error);
    }
  }, [activeGameId, myId]);

  const onToggleMockStreams = useCallback(() => {
    handleToggleMockStreams();
    setIsMenuOpen(false);
  }, [handleToggleMockStreams]);

  const onMuteAll = useCallback(() => {
    muteAllExceptGM(activeGameGm);
    setIsMenuOpen(false);
  }, [activeGameGm, muteAllExceptGM]);

  const onUnmuteAll = useCallback(() => {
    unmuteAll();
    setIsMenuOpen(false);
  }, [unmuteAll]);

  const onDisableAllCameras = useCallback(() => {
    disableAllCamerasExceptGM(activeGameGm);
    setIsMenuOpen(false);
  }, [activeGameGm, disableAllCamerasExceptGM]);

  const onEnableAllCameras = useCallback(() => {
    enableAllCameras();
    setIsMenuOpen(false);
  }, [enableAllCameras]);

  const onRestartGame = useCallback(() => {
    if (!activeGameId) return;

    setIsMenuOpen(false);
    rootStore.modalStore.openModal(ModalNames.ConfirmRestartModal, {
      onConfirm: () => restartGame(activeGameId),
    });
  }, [activeGameId, restartGame]);

  const onFinishGame = useCallback(() => {
    if (!activeGameId) return;

    finishGame(activeGameId);
    setIsMenuOpen(false);
  }, [activeGameId, finishGame]);

  const onLeaveGame = useCallback(() => {
    setIsMenuOpen(false);
    navigate(routes.home);
  }, [navigate]);

  return {
    isMenuOpen,
    setIsMenuOpen,
    isIGM,
    mockStreamsEnabled,
    gameFlow,
    onMakeMeGM,
    onToggleMockStreams,
    onMuteAll,
    onUnmuteAll,
    onDisableAllCameras,
    onEnableAllCameras,
    onRestartGame,
    onFinishGame,
    onLeaveGame,
    // TODO: remove — temporary for layout stress-testing
    onAddTestUsers,
    isAddingTestUsers,
  };
};

import { useMemo } from "react";

import { useMockStreams } from "@/hooks/useMockStreams";
import { rootStore } from "@/store/rootStore.ts";

type GridConfig = {
  two: boolean;
  three: boolean;
  four: boolean;
  five: boolean;
};

export const useGridLayout = (): GridConfig => {
  const { gamesStore } = rootStore;
  const { speaker } = gamesStore;
  const { streamsLength } = useMockStreams();

  return useMemo(() => {
    return {
      two: streamsLength <= 4,
      three: streamsLength > 4 && streamsLength <= 6,
      four: streamsLength > 6 && streamsLength <= 12,
      five: streamsLength > 12 || !!speaker,
    };
  }, [streamsLength, speaker]);
};

import { useMemo } from "react";

import { useMockStreams } from "@/hooks/useMockStreams";
import { rootStore } from "@/store/rootStore.ts";

type GridConfig = {
  two: boolean;
  three: boolean;
  four: boolean;
  five: boolean;
  sandwich: boolean;
};

export const useGridLayout = (): GridConfig => {
  const { gamesStore } = rootStore;
  const { speaker } = gamesStore;
  const { streamsLength } = useMockStreams();

  return useMemo(() => {
    const hasSpeaker = !!speaker;
    const isLargeGame = streamsLength > 10;

    return {
      two: streamsLength <= 4,
      three: streamsLength > 4 && streamsLength <= 6,
      four: streamsLength > 6 && streamsLength <= 12 && !hasSpeaker,
      // Classic speaker layout: speaker sits at top spanning rows 1–2
      five: (streamsLength > 12 && !hasSpeaker) || (hasSpeaker && !isLargeGame),
      // Sandwich layout: small row / big speaker / small row (11+ player games)
      sandwich: hasSpeaker && isLargeGame,
    };
  }, [streamsLength, speaker]);
};

import { useTracks } from "@livekit/components-react";
import { Participant, Track } from "livekit-client";
import { useCallback, useMemo, useState } from "react";

import { rootStore } from "@/store/rootStore.ts";
import { UserId } from "@/types/user.types.ts";

// Create a mock participant object that implements the basic Participant interface
const createMockParticipant = (identity: string, name: string): Participant => {
  return {
    identity,
    name,
    sid: `mock_${identity}`,
    isLocal: false,
    connectionQuality: "excellent",
    isSpeaking: false,
    audioLevel: 0,
    permissions: {},
    metadata: "",
    joinedAt: new Date(),
    // Add minimal required methods and properties
    getTrackPublication: () => undefined,
    getTrackPublications: () => [],
    getTracks: () => [],
    isCameraEnabled: () => false,
    isMicrophoneEnabled: () => false,
    isScreenShareEnabled: () => false,
    // Add event emitter methods
    on: () => {},
    off: () => {},
    emit: () => false,
    addListener: () => {},
    removeListener: () => {},
    removeAllListeners: () => {},
  } as unknown as Participant;
};

export const useMockStreams = () => {
  const { usersStore, gamesStore } = rootStore;
  const { myId, getUser } = usersStore;
  const { activeGamePlayers } = gamesStore;
  const tracks = useTracks([Track.Source.Camera]);
  const [mockStreamsEnabled, setMockStreamsEnabled] = useState(false);

  // Find my current track for cloning
  const myTrack = useMemo(() => {
    return tracks.find((trackRef) => trackRef.participant?.isLocal)?.publication
      ?.track;
  }, [tracks]);

  // Create mock participants based on activeGamePlayers
  const mockTracks = useMemo(() => {
    if (!mockStreamsEnabled || !myTrack || !activeGamePlayers.length) {
      return [];
    }

    return activeGamePlayers
      .filter((playerId) => playerId !== myId) // Exclude myself
      .map((playerId: UserId) => {
        const user = getUser(playerId);

        // Create a mock participant that works with GameVideo component
        const mockParticipant = createMockParticipant(
          playerId,
          user?.nikName || `Player ${playerId.slice(-4)}`
        );

        return {
          participant: mockParticipant,
          publication: {
            track: myTrack, // Use my video track for all mock streams
            source: Track.Source.Camera,
            kind: Track.Kind.Video,
            trackSid: `mock_${playerId}_track`,
            trackName: `mock_${playerId}_camera`,
          },
          source: Track.Source.Camera,
        };
      });
  }, [mockStreamsEnabled, myTrack, activeGamePlayers, myId, getUser]);

  // Combine real tracks with mock tracks
  const allTracks = useMemo(() => {
    return mockStreamsEnabled ? [...tracks, ...mockTracks] : tracks;
  }, [tracks, mockTracks, mockStreamsEnabled]);

  const handleToggleMockStreams = useCallback(() => {
    if (!activeGamePlayers.length) {
      console.log("No active game players found");
      return;
    }

    const newMockState = !mockStreamsEnabled;
    setMockStreamsEnabled(newMockState);

    console.log(
      newMockState
        ? `Created ${activeGamePlayers.length - 1} mock streams based on activeGamePlayers`
        : "Disabled mock streams"
    );
    console.log("Active players:", activeGamePlayers);
  }, [activeGamePlayers, mockStreamsEnabled]);

  return {
    mockStreamsEnabled,
    allTracks,
    streamsLength: allTracks.length,
    handleToggleMockStreams,
    myTrack,
  };
};

