export const useMockStreams = () => {
  const { usersStore, gamesStore } = rootStore;
  const { myId, getUser } = usersStore;
  const { activeGamePlayers, mockStreamsEnabled, setMockStreamsEnabled } = gamesStore;
  const tracks = useTracks([Track.Source.Camera]);

  // Find my current track for cloning
  const myTrack = useMemo(() => {
    return tracks.find((trackRef) => trackRef.participant?.isLocal)?.publication
      ?.track;
  }, [tracks]);

  // Create mock participants based on activeGamePlayers.
  // myTrack is used when available (clones local camera to all containers),
  // but is no longer required — omitting it renders avatar/name placeholders
  // which is sufficient for layout stress-testing.
  const mockTracks = useMemo(() => {
    if (!mockStreamsEnabled || !activeGamePlayers.length) {
      return [];
    }

    return activeGamePlayers
      .filter((playerId) => playerId !== myId) // Exclude myself
      .map((playerId: UserId) => {
        const user = getUser(playerId);

        // Create a mock participant that works with GameVideo component
        const mockParticipant = createMockParticipant(
          playerId,
          user?.nikName || `Player ${playerId.slice(-4)}`
        );

        return {
          participant: mockParticipant,
          // When myTrack exists, clone the local stream into every container.
          // When it is undefined the publication resolves to null and GameVideo
          // falls back to an avatar/name placeholder — fine for layout testing.
          publication: myTrack
            ? {
                track: myTrack,
                source: Track.Source.Camera,
                kind: Track.Kind.Video,
                trackSid: `mock_${playerId}_track`,
                trackName: `mock_${playerId}_camera`,
              }
            : null,
          source: Track.Source.Camera,
        };
      });
  }, [mockStreamsEnabled, myTrack, activeGamePlayers, myId, getUser]);

  // Combine real tracks with mock tracks
  const allTracks = useMemo(() => {
    return mockStreamsEnabled ? [...tracks, ...mockTracks] : tracks;
  }, [tracks, mockTracks, mockStreamsEnabled]);

  const handleToggleMockStreams = useCallback(() => {
    if (!activeGamePlayers.length) {
      console.log("No active game players found");
      return;
    }

    const newMockState = !mockStreamsEnabled;
    setMockStreamsEnabled(newMockState);

    console.log(
      newMockState
        ? `Created ${activeGamePlayers.length - 1} mock streams based on activeGamePlayers`
        : "Disabled mock streams"
    );
    console.log("Active players:", activeGamePlayers);
  }, [activeGamePlayers, mockStreamsEnabled, setMockStreamsEnabled]);

  return {
    mockStreamsEnabled,
    allTracks,
    streamsLength: allTracks.length,
    handleToggleMockStreams,
    myTrack,
  };
};

import { makeAutoObservable, toJS } from "mobx";
import { makePersistable } from "mobx-persist-store";

import { UserId } from "@/types/user.types.ts";
import { usersStore } from "./usersStore.ts";

import { initialGameFlow } from "../helpers/createGameObj.ts";
import {
  isFirstNightActive,
  isImmunityPhaseActive,
} from "../helpers/immunity.ts";
import {
  IGame,
  IGameFlow,
  IGameShort,
  NightRoles,
  Roles,
} from "../types/game.types.ts";

export class GamesStore {
  _games: IGameShort[] = [];
  _activeGame: IGame | null = null;
  forceMutedUsers: UserId[] = [];
  // Persisted UI state — survives component unmount/remount during voting
  isDealingComplete: boolean = false;
  isRoleRevealed: boolean = false;

  constructor() {
    makeAutoObservable(this, {}, { autoBind: true });
    void makePersistable(this, {
      name: "Users_mobx_gameFlow",
      properties: ["_games", "_activeGame"],
      storage: sessionStorage,
    });
  }

  setGames(games: IGameShort[]) {
    this._games = games;
  }

  updateGames(newGame: IGameShort) {
    // If the game was explicitly deactivated (e.g. manually) — remove from list
    if (!newGame.isActive) {
      this._games = this._games.filter((game) => game.id !== newGame.id);
      return;
    }

    const isGameExist = this._games.some((game) => game.id === newGame.id);

    if (!isGameExist) {
      this._games = [...this._games, newGame];
      return;
    }

    // Update in place — handles isStarted changes (start/restart) in real time
    this._games = this._games.map((game) =>
      game.id === newGame.id ? newGame : game
    );
  }

  updateGame(game: IGame) {
    const wasStarted = this._activeGame?.gameFlow?.isStarted;
    const isNowStarted = game.gameFlow?.isStarted;

    // Detect restart: game was started but now it's not (returning to lobby)
    if (wasStarted && !isNowStarted) {
      this.restartGameStore();
    }

    this._activeGame = game;
  }

  removeActiveGame() {
    this._activeGame = null;
    this.restartGameStore();
  }

  restartGameStore() {
    this.forceMutedUsers = [];
    this.isDealingComplete = false;
    this.isRoleRevealed = false;
  }

  setForceMutedUser(userId: UserId, isMuted: boolean) {
    if (isMuted) {
      if (!this.forceMutedUsers.includes(userId)) {
        this.forceMutedUsers.push(userId);
      }
    } else {
      this.forceMutedUsers = this.forceMutedUsers.filter((id) => id !== userId);
    }
  }

  isUserForceMuted(userId: UserId): boolean {
    return this.forceMutedUsers.includes(userId);
  }

  updateGameFlow(newFlow: Partial<IGameFlow>) {
    const flow = this._activeGame?.gameFlow;

    if (!flow) return;

    this.updateGame({
      ...this._activeGame,
      gameFlow: { ...flow, ...newFlow },
    } as IGame);
  }

  setToProposed(playerId: UserId, proposerId: UserId) {
    const gameFlow = this._activeGame?.gameFlow;
    if (!gameFlow) return;

    const proposed = gameFlow.proposed;
    const proposedBy = gameFlow.proposedBy || {};

    if (proposed.includes(playerId)) return;

    const newProposed = [...proposed, playerId];
    const newProposedBy = { ...proposedBy, [playerId]: proposerId };

    this.updateGameFlow({ proposed: newProposed, proposedBy: newProposedBy });
  }

  addVoted({
    targetUserId,
    voterId,
  }: {
    targetUserId: UserId;
    voterId: UserId;
  }) {
    const voted = this._activeGame?.gameFlow?.voted;

    if (!voted) return;

    const currentVoters = voted[targetUserId] || [];
    if (currentVoters.includes(voterId)) return;

    const newVoted = {
      ...voted,
      [targetUserId]: [...currentVoters, voterId],
    };

    this.updateGameFlow({ voted: newVoted });
  }

  addShoot({
    targetUserId,
    shooterId,
    shot,
  }: {
    targetUserId: UserId;
    shooterId: UserId;
    shot?: { x: number; y: number };
  }) {
    const shoot = this._activeGame?.gameFlow?.shoot ?? {};
    const existing = shoot[targetUserId] ?? { shooters: [], shots: [] };
    const defaultShot = { x: 50, y: 50 };

    const newShoot = {
      ...shoot,
      [targetUserId]: {
        shooters: [...existing.shooters, shooterId],
        shots: [...existing.shots, shot ?? defaultShot],
      },
    };

    this.updateGameFlow({ shoot: newShoot });
  }

  isUserGM(userId?: string) {
    if (!userId) return false;

    return this.activeGameGm === userId;
  }

  get activeGame() {
    return toJS(this._activeGame);
  }

  get activeGameId(): string | undefined {
    return this.activeGame?.id;
  }

  get activeGameGm() {
    return this.activeGame?.gm;
  }

  get activeGameOwner() {
    return this.activeGame?.owner;
  }

  get activeGamePlayers() {
    return toJS(this.activeGame?.players) ?? [];
  }

  get activeGamePlayersWithoutGM() {
    return this.activeGamePlayers.filter(
      (player) => player !== this.activeGameGm
    );
  }

  get activeGameKilledPlayers() {
    return toJS(this.gameFlow.killed) ?? [];
  }

  get activeGameImmunePlayer(): UserId | null {
    const id = this.gameFlow.immunePlayer ?? null;

    if (!id) return null;

    // FE-fallback: якщо BE ще не встиг скинути поле на перехідній фазі,
    // "derived" перевірка робить гравця не-імунним автоматично.
    const phaseOk = isImmunityPhaseActive(
      this.gameFlow,
      isFirstNightActive(this.activeGame)
    );

    return phaseOk ? id : null;
  }

  get isAnyoneImmune(): boolean {
    return !!this.activeGameImmunePlayer;
  }

  isUserImmune(userId?: UserId): boolean {
    if (!userId) return false;

    return this.activeGameImmunePlayer === userId;
  }

  get activeGameAlivePlayers() {
    return this.activeGamePlayersWithoutGM.filter(
      (player) => !this.activeGameKilledPlayers.includes(player)
    );
  }

  get activeGameRoles() {
    const activeGame = this.activeGame;

    if (!activeGame) return null;

    const { mafia, sheriff, citizens, doctor, maniac, prostitute } = activeGame;

    return toJS({
      mafia,
      sheriff,
      citizens,
      doctor,
      maniac,
      prostitute,
      don: mafia?.[0],
    });
  }

  get nightRoles(): NightRoles[] {
    const roles = this.activeGameRoles;

    if (!roles) return [];

    const nightRoleOrder: NightRoles[] = [
      Roles.Mafia, Roles.Don, Roles.Sheriff, Roles.Prostitute, Roles.Doctor,
    ];

    const nightRoles = Object.entries(roles)
      .filter(([key, value]) => {
        if (!value || key === Roles.Citizen) return false;

        // If it's Mafia group but we only have 1 (who is also the Don), hide Mafia group option
        if (
          key === Roles.Mafia &&
          Array.isArray(value) &&
          value.length === 1
        ) {
          return false;
        }

        return true;
      })
      .map(([key]) => key);

    return nightRoles.sort(
      (a, b) => nightRoleOrder.indexOf(a as NightRoles) - nightRoleOrder.indexOf(b as NightRoles)
    ) as NightRoles[];
  }

  get observers(): UserId[] {
    return toJS(this.activeGame?.observers) ?? [];
  }

  get isMeObserver(): boolean {
    const myId = usersStore.myId;
    if (!myId) return false;
    return this.observers.includes(myId);
  }

  get gameFlow() {
    return toJS(this.activeGame?.gameFlow) ?? initialGameFlow;
  }

  get blockedPlayer() {
    return this.gameFlow.prostituteBlock ?? "";
  }

  get speaker() {
    return this.gameFlow.speaker;
  }

  get games() {
    return toJS(this._games);
  }

  getUserRole(id: UserId) {
    const roles = this.activeGameRoles;

    if (!roles) return Roles.Unknown;

    if (roles.mafia?.includes(id)) {
      return roles.mafia[0] === id ? Roles.Don : Roles.Mafia;
    }
    if (roles.citizens?.includes(id)) return Roles.Citizen;
    if (roles.sheriff === id) return Roles.Sheriff;
    if (roles.doctor === id) return Roles.Doctor;
    if (roles.maniac === id) return Roles.Maniac;
    if (roles.prostitute === id) return Roles.Prostitute;
    if (this.isUserGM(id)) return Roles.GM;

    return Roles.Unknown;
  }
}

export const gamesStore = new GamesStore();

